void invert_mapping(float *input,
                    float *output,
                    int npoints,
                    int nfeatures)
{
    int total_threads = num_blocks * num_threads;
#pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < npoints; point_id++) {
        for (int i = 0; i < nfeatures; i++) {
            output[point_id + npoints * i] = input[point_id * nfeatures + i];
        }
    }
}

int kmeansPoint(float *features,
                int nfeatures,
                int npoints,
                int nclusters,
                int *membership,
                float *clusters,
                float *block_clusters,
                int *block_deltas)
{
    int delta = 0;
    int total_threads = num_blocks * num_threads;

#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int total_threads = omp_get_num_threads();
        int points_per_thread = (npoints + total_threads - 1) / total_threads;
        int start = tid * points_per_thread;
        int end = start + points_per_thread;
        if (end > npoints) end = npoints;

        int local_delta = 0;

        for (int point_id = start; point_id < end; point_id++) {
            float min_dist = FLT_MAX;
            int index = -1;

            for (int i = 0; i < nclusters; i++) {
                int cluster_base_index = i * nfeatures;
                float ans = 0.0f;

                for (int j = 0; j < nfeatures; j++) {
                    float diff = features[point_id + j * npoints] - clusters[cluster_base_index + j];
                    ans += diff * diff;
                }

                float dist = ans;
                if (dist < min_dist) {
                    min_dist = dist;
                    index = i;
                }
            }

            if (membership[point_id] != index) {
                local_delta++;
                membership[point_id] = index;
            }
        }

#pragma omp atomic
        delta += local_delta;
    }

    // Reduction for block_clusters and block_deltas is omitted as it is GPU-specific
    return delta;
}

